 12	import React from 'react';
 13	import { useTranslation } from 'react-i18next';
 14	import { useBoolean } from '../hooks/useBoolean';
 15	import { padLeadingZero } from '../value-utils';
 16	import './precision-time-picker.css';
 17	
 18	interface PrecisionTimePickerProps {
 19	  time: string;
 20	  onChange?: (time: string, hours?: number, minutes?: number, seconds?: number) => void;
 21	}
 22	
 23	const validTimeStringRegex = /^\d{2}:\d{2}(:\d{2}(\.\d+)?)?$/;
 24	
 25	const parseTimeString = (
 26	  time: string,
 27	): { hours: number; minutes: number; seconds: number } | null => {
 28	  if (!validTimeStringRegex.test(time)) {
 29	    return null;
 30	  }
 31	
 32	  const parts = time.split(':');
 33	
 34	  if (parts.length >= 2) {
 35	    const hours = parseInt(parts[0], 10);
 36	    const minutes = parseInt(parts[1], 10);
 37	    const seconds = parts.length >= 3 ? parseFloat(parts[2]) : 0;
 38	
 39	    if (!isNaN(hours) && !isNaN(minutes) && !isNaN(seconds)) {
 40	      if (hours >= 24 || minutes >= 60 || seconds >= 60) {
 41	        return null;
 42	      } else {
 43	        return { hours, minutes, seconds };
 44	      }
 45	    }
 46	  }
 47	
 48	  return null;
 49	};
 50	
 51	const timeMenuItemsBuilder: () => Array<string> = () => {
 52	  const items = [];
 53	
 54	  for (let hours = 0; hours < 24; hours++) {
 55	    for (let minutes = 0; minutes < 60; minutes += 30) {
 56	      items.push(`${padLeadingZero(hours)}:${padLeadingZero(minutes)}`);
 57	    }
 58	  }
 59	
 60	  return items;
 61	};
 62	
 63	const timeMenuItems = timeMenuItemsBuilder();
 64	
 65	export const PrecisionTimePicker: React.FC<PrecisionTimePickerProps> = ({ onChange, time }) => {
 66	  const { t } = useTranslation('plugin__logging-view-plugin');
 67	
 68	  const [value, setValue] = React.useState(time);
 69	  const [isValid, setIsvalid] = React.useState(true);
 70	  const { value: isMenuOpen, setTrue: openMenu, setFalse: closeMenu } = useBoolean(false);
 71	  const inputRef = React.useRef<HTMLInputElement | null>(null);
 72	  const menuRef = React.useRef<HTMLDivElement | null>(null);
 73	
 74	  const handleValueChange = (changedValue: string) => {
 75	    setValue(changedValue);
 76	    const parsedTime = parseTimeString(changedValue);
 77	
 78	    if (parsedTime) {
 79	      setIsvalid(true);
 80	      onChange?.(changedValue, parsedTime.hours, parsedTime.minutes, parsedTime.seconds);
 81	    } else {
 82	      setIsvalid(false);
 83	      onChange?.(changedValue, undefined, undefined, undefined);
 84	    }
 85	
 86	    closeMenu();
 87	  };
 88	
 89	  const onDocumentClick = (event: MouseEvent | undefined) => {
 90	    if (
 91	      inputRef.current !== event?.target &&
 92	      !menuRef.current?.contains(event?.target as HTMLElement)
 93	    ) {
 94	      closeMenu();
 95	    }
 96	  };
 97	
 98	  const handleMenuSelect = (_?: React.MouseEvent, itemId?: string | number) => {
 99	    if (itemId && typeof itemId === 'string') {
100	      handleValueChange(itemId);
101	    }
102	  };
103	
104	  const popper = (
105	    <Menu
106	      id="time-select-menu"
107	      onSelect={handleMenuSelect}
108	      className="lv-plugin__time-picker__time-options"
109	      ref={menuRef}
110	    >
111	      <MenuContent>
112	        <MenuList>
113	          {timeMenuItems.map((item, index) => (
114	            <MenuItem key={index} onClick={() => handleValueChange(item)} ref={null} itemID={item}>
115	              {item}
116	            </MenuItem>
117	          ))}
118	        </MenuList>
119	      </MenuContent>
120	    </Menu>
121	  );
122	
123	  const trigger = (
124	    <div>
125	      <TextInput
126	        value={value}
127	        onFocus={openMenu}
128	        type="text"
129	        onChange={(_event, changedValue: string) => handleValueChange(changedValue)}
130	        aria-label="Precision time picker"
131	        isRequired
132	        validated={isValid ? undefined : ValidatedOptions.error}
133	        className="lv-plugin__time-picker__input"
134	        ref={inputRef}
135	      />
136	      {!isValid && (
137	        <HelperText className="lv-plugin__time-picker__error">
138	          <HelperTextItem variant="error">{t('Invalid time format')}</HelperTextItem>
139	        </HelperText>
140	      )}
141	    </div>
142	  );
143	
144	  return (
145	    <Popper
146	      trigger={trigger}
147	      popper={popper}
148	      isVisible={isMenuOpen}
149	      onDocumentClick={onDocumentClick}
150	    />
151	  );
152	};

